165	func (s *axonSmokeServer) handleQuery(t *testing.T, w http.ResponseWriter, r *http.Request) {
166		t.Helper()
167		defer r.Body.Close()
168	
169		var req struct {
170			Query     string         `json:"query"`
171			Variables map[string]any `json:"variables"`
172		}
173		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
174			http.Error(w, err.Error(), http.StatusBadRequest)
175			return
176		}
177	
178		write := func(payload any) {
179			w.Header().Set("Content-Type", "application/json")
180			_ = json.NewEncoder(w).Encode(map[string]any{"data": payload})
181		}
182	
183		switch req.Query {
184		case createBeadMutation:
185			rawInput, _ := json.Marshal(req.Variables["input"])
186			var input BeadInput
187			if err := json.Unmarshal(rawInput, &input); err != nil {
188				http.Error(w, err.Error(), http.StatusBadRequest)
189				return
190			}
191			b := bead.Bead{
192				ID:           input.ID,
193				Title:        input.Title,
194				Status:       input.Status,
195				Priority:     input.Priority,
196				IssueType:    input.IssueType,
197				Owner:        input.Owner,
198				Labels:       append([]string(nil), input.Labels...),
199				Parent:       input.Parent,
200				Description:  input.Description,
201				Acceptance:   input.Acceptance,
202				Notes:        input.Notes,
203				Dependencies: dependencyInputsToLocal(input.Dependencies),
204				Extra:        cloneStringAnyMap(input.Extra),
205			}
206			if err := s.store.Create(context.Background(), &b); err != nil {
207				http.Error(w, err.Error(), http.StatusBadRequest)
208				return
209			}
210			write(map[string]any{"createEntity": BeadFromLocal(b)})
211		case updateBeadMutation:
212			id, _ := req.Variables["id"].(string)
213			rawInput, _ := json.Marshal(req.Variables["input"])
214			var input BeadInput
215			if err := json.Unmarshal(rawInput, &input); err != nil {
216				http.Error(w, err.Error(), http.StatusBadRequest)
217				return
218			}
219			mutate := func(b *bead.Bead) error {
220				b.Title = input.Title
221				b.Priority = input.Priority
222				b.IssueType = input.IssueType
223				b.Owner = input.Owner
224				b.Labels = append([]string(nil), input.Labels...)
225				b.Parent = input.Parent
226				b.Description = input.Description
227				b.Acceptance = input.Acceptance
228				b.Notes = input.Notes
229				b.Dependencies = dependencyInputsToLocal(input.Dependencies)
230				b.Extra = cloneStringAnyMap(input.Extra)
231				return nil
232			}
233			if err := s.store.UpdateWithLifecycleStatus(id, input.Status, bead.LifecycleTransitionOptions{}, mutate); err != nil {
234				http.Error(w, err.Error(), http.StatusBadRequest)
235				return
236			}
237			updated, err := s.store.Get(context.Background(), id)
238			if err != nil {
239				http.Error(w, err.Error(), http.StatusBadRequest)
240				return
241			}
242			write(map[string]any{"updateEntity": BeadFromLocal(*updated)})
243		case getBeadQuery:
244			id, _ := req.Variables["id"].(string)
245			b, err := s.store.Get(context.Background(), id)
246			if err != nil {
247				write(map[string]any{"ddxBead": nil})
248				return
249			}
250			write(map[string]any{"ddxBead": BeadFromLocal(*b)})
251		case listBeadsQuery:
252			beads, err := s.store.ReadAll(context.Background())
253			if err != nil {
254				http.Error(w, err.Error(), http.StatusBadRequest)
255				return
256			}
257			out := make([]Bead, 0, len(beads))
258			for _, b := range beads {
259				out = append(out, BeadFromLocal(b))
260			}
261			write(map[string]any{"ddxBeads": out})
262		default:
263			http.Error(w, "unsupported query", http.StatusBadRequest)
264		}
265	}
