267	func (s *axonSmokeServer) handleSubscription(t *testing.T, w http.ResponseWriter, r *http.Request, projectDir string) {
268		t.Helper()
269	
270		conn, err := s.upgrader.Upgrade(w, r, nil)
271		if err != nil {
272			http.Error(w, err.Error(), http.StatusBadRequest)
273			return
274		}
275		defer conn.Close()
276	
277		var msg graphqlWSMessage
278		if err := conn.ReadJSON(&msg); err != nil {
279			return
280		}
281		if msg.Type != "connection_init" {
282			return
283		}
284		if err := conn.WriteJSON(graphqlWSMessage{Type: "connection_ack"}); err != nil {
285			return
286		}
287	
288		if err := conn.ReadJSON(&msg); err != nil {
289			return
290		}
291		if msg.Type != "subscribe" {
292			return
293		}
294	
295		var payload struct {
296			Query     string         `json:"query"`
297			Variables map[string]any `json:"variables"`
298		}
299		if err := json.Unmarshal(msg.Payload, &payload); err != nil {
300			return
301		}
302		if payload.Query != changeEventsSubscription {
303			return
304		}
305		projectID, _ := payload.Variables["projectID"].(string)
306		if projectID != projectDir {
307			return
308		}
309	
310		subCh, unsub := s.hub.SubscribeLifecycle(projectID)
311		defer unsub()
312		close(s.subscribed)
313	
314		for {
315			select {
316			case evt, ok := <-subCh:
317				if !ok {
318					return
319				}
320				raw, err := json.Marshal(map[string]any{
321					"data": map[string]any{
322						"changeEvents": ChangeEventFromLifecycle(evt),
323					},
324				})
325				if err != nil {
326					return
327				}
328				if err := conn.WriteJSON(graphqlWSMessage{ID: msg.ID, Type: "next", Payload: raw}); err != nil {
329					return
330				}
331			case <-r.Context().Done():
332				return
333			}
334		}
335	}
336	
337	func waitForChangeEvent(t *testing.T, stream <-chan ChangeEvent, timeout time.Duration) ChangeEvent {
338		t.Helper()
339		ctx, cancel := context.WithTimeout(context.Background(), timeout)
340		defer cancel()
341	
342		select {
343		case evt, ok := <-stream:
344			if !ok {
345				t.Fatal("subscription closed before expected event arrived")
346			}
347			return evt
348		case <-ctx.Done():
349			t.Fatalf("timed out waiting for change event: %v", ctx.Err())
350			return ChangeEvent{}
351		}
352	}
353	
354	func dependencyInputsToLocal(src []DependencyInput) []bead.Dependency {
355		if len(src) == 0 {
356			return nil
357		}
358		out := make([]bead.Dependency, 0, len(src))
359		for _, dep := range src {
360			out = append(out, bead.Dependency{
361				IssueID:     dep.IssueID,
362				DependsOnID: dep.DependsOnID,
363				Type:        dep.Type,
364				CreatedAt:   dep.CreatedAt,
365				CreatedBy:   dep.CreatedBy,
366				Metadata:    dep.Metadata,
367			})
368		}
369		return out
370	}
